import React from 'react';
import { Linking, Platform } from 'react-native';
import { useNavigation } from '@react-navigation/native';
import { createStackNavigator } from '@react-navigation/stack';

// Define the stack navigator for the application
const Stack = createStackNavigator();

// Define your Profile and Payment screens here
const ProfileScreen = () => <Text>Profile Screen</Text>;
const PaymentConfirmScreen = () => <Text>Payment Confirmation Screen</Text>;

// Custom Linking function for handling deep links
function linking(navigation) {
  if (Platform.OS === 'ios') {
    Linking.addEventListener('url', handleOpenURL);
  } else {
    Linking.addEventListener('url', handleCustomUrlScheme);
  }

  function handleOpenURL(event) {
    const isDeepLink = event.url.startsWith('myapp://');
    const isInvalid = !isDeepLink;

    if (isDeepLink) {
      Linking.removeEventListener('url', handleOpenURL);
      handleDeepLink(event);
    } else {
      console.log(`Dismissed ${event.url}`);
    }
  }

  function handleCustomUrlScheme(event) {
    const isDeepLink = event.url.startsWith('myapp://');
    const isInvalid = !isDeepLink;

    if (isDeepLink) {
      Linking.removeEventListener('url', handleCustomUrlScheme);
      const url = event.url.split('/')[2];
      navigation.navigate(url === 'profile' ? 'ProfileScreen' : 'PaymentConfirmScreen');
    } else {
      console.log(`Dismissed ${event.url}`);
    }
  }

  function handleDeepLink(event) {
    Linking.removeEventListener('url', handleOpenURL);
    Linking.removeEventListener('url', handleCustomUrlScheme);
    const url = event.url.split('/')[3];
    navigation.navigate(url === 'profile' ? 'ProfileScreen' : 'PaymentConfirmScreen', { id: Number(url.substring(6)) });
  }
}

// Create a function component for the App
const App = () => {
  const navigation = useNavigation();
  linking(navigation);

  return (
    <Stack.Navigator initialRouteName="PaymentConfirmScreen">
      <Stack.Screen name="ProfileScreen" component={ProfileScreen} />
      <Stack.Screen name="PaymentConfirmScreen" component={PaymentConfirmScreen} />
    </Stack.Navigator>
  );
};

export default App;